SELECT u.id, u.username, u.nickname, u.phone, u.email, u.avatar, u.dept_id, u.position_id, u.tenant_id, u.account_type, u.status, u.last_login_time, u.last_login_ip, u.create_time, u.update_time FROM sys_user u LEFT JOIN sys_dept d ON u.dept_id = d.id
AND u.deleted = 0
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.nickname LIKE CONCAT('%', #{nickname}, '%')
AND u.phone_suffix = #{phone}
AND u.phone_suffix LIKE CONCAT('%', #{phone}, '%')
AND u.email_suffix = #{email}
AND u.status = #{status}
AND u.dept_id = #{deptId}
ORDER BY u.create_time DESC

SELECT u.id, u.username, u.nickname, u.phone, u.email, u.avatar, u.dept_id, u.position_id, u.tenant_id, u.account_type, u.status, u.last_login_time, u.last_login_ip, u.create_time, u.update_time FROM sys_user u LEFT JOIN sys_dept d ON u.dept_id = d.id
AND u.deleted = 0
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.nickname LIKE CONCAT('%', #{nickname}, '%')
AND u.phone_suffix = #{phone}
AND u.phone_suffix LIKE CONCAT('%', #{phone}, '%')
AND u.email_suffix = #{email}
AND u.status = #{status}
AND u.dept_id = #{deptId}
ORDER BY u.create_time DESC

SELECT DISTINCT ur.user_id FROM sys_user_role ur INNER JOIN sys_user u ON ur.user_id = u.id WHERE ur.role_id IN
#{roleId}
AND u.deleted = 0 AND u.status = 1

SELECT DISTINCT u.id FROM sys_user u WHERE u.dept_id IN
#{deptId}
AND u.deleted = 0 AND u.status = 1
